import { IMessageDataWrapper, IMessageParser } from '@nitrots/nitro-renderer';

export class TradeOpenParser implements IMessageParser
{
private _sessionId = 0;
private _userAId = 0;
private _userBId = 0;
private _usernameA = '';
private _usernameB = '';

public flush(): boolean
{
this._sessionId = 0;
this._userAId = 0;
this._userBId = 0;
this._usernameA = '';
this._usernameB = '';
return true;
}

public parse(wrapper: IMessageDataWrapper): boolean
{
if(!wrapper) return false;

// Must match TradeOpenComposer.java EXACTLY
this._sessionId = wrapper.readInt();
this._userAId = wrapper.readInt();
this._userBId = wrapper.readInt();
this._usernameA = wrapper.readString();
this._usernameB = wrapper.readString();

return true;
}

public get sessionId(): number { return this._sessionId; }
public get userAId(): number { return this._userAId; }
public get userBId(): number { return this._userBId; }
public get usernameA(): string { return this._usernameA; }
public get usernameB(): string { return this._usernameB; }
}
